SELECT visit_date, COUNT(DISTINCT patient_id) AS patient_count
FROM patient_visits
GROUP BY visit_date;

SELECT visit_date, diagnosis
FROM patient_visits
ORDER BY visit_date ASC;

SELECT COUNT(patient_id) AS total_patients, first_name
FROM patient_records
LIMIT 1;

SELECT COUNT(DISTINCT patient_id) AS number_of_patients
FROM appointments
WHERE status IN ('Booked', 'Arrived', 'Completed');

SELECT AVG(rating) AS average_rating
FROM patient_feedback
WHERE facility_id = 1;

SELECT AVG(rating) AS average_feedback_rating
FROM patient_feedback
WHERE facility_id = 1;

SELECT visit_date
FROM patient_visits
WHERE visit_id = 1;
